def tool(name):
    def register(function):
        TOOLS[name] = function
        return function

    return register


def resolve_workspace_path(path):
    target = (WORKSPACE_ROOT / path).resolve()
    try:
        target.relative_to(WORKSPACE_ROOT)
    except ValueError:
        raise ValueError("Path must stay inside the current workspace")
    return target


@tool("list_dir")
def list_dir(path="."):
    target = resolve_workspace_path(path)
    if not target.exists():
        raise FileNotFoundError(f"No such directory: {path}")
    if not target.is_dir():
        raise NotADirectoryError(f"Not a directory: {path}")

    entries = []
    for child in sorted(target.iterdir(), key=lambda item: (not item.is_dir(), item.name.lower())):
        kind = "directory" if child.is_dir() else "file"
        entries.append({"name": child.name, "type": kind})

    return json.dumps({"path": str(target.relative_to(WORKSPACE_ROOT)), "entries": entries}, indent=2)


@tool("find_files")
def find_files(query, path=".", max_results=50):
    if not query:
        raise ValueError("query must not be empty")

    target = resolve_workspace_path(path)
    if not target.exists():
        raise FileNotFoundError(f"No such path: {path}")

    max_results = max(1, min(int(max_results), 200))
    query_lower = query.lower()
    matches = []
    paths = [target] if target.is_file() else iter_paths(target)

    for item in paths:
        if query_lower in item.name.lower():
            kind = "directory" if item.is_dir() else "file"
            matches.append({"path": str(item.relative_to(WORKSPACE_ROOT)), "type": kind})
            if len(matches) >= max_results:
                break

    return json.dumps(
        {"query": query, "path": path, "matches": matches, "truncated": len(matches) >= max_results},
        ensure_ascii=False,
        indent=2,
    )


@tool("read_file")
def read_file(path):
    target = resolve_workspace_path(path)
    if not target.exists():
        raise FileNotFoundError(f"No such file: {path}")
    if not target.is_file():
        raise IsADirectoryError(f"Not a file: {path}")

    data = target.read_bytes()
    truncated = len(data) > MAX_FILE_BYTES
    data = data[:MAX_FILE_BYTES]

    try:
        text = data.decode("utf-8")
    except UnicodeDecodeError:
        raise ValueError(f"File is not valid UTF-8 text: {path}")

    if truncated:
        text += f"\n\n[truncated after {MAX_FILE_BYTES} bytes]"
    return text


@tool("search_files")
def search_files(query, path=".", max_results=50):
    if not query:
        raise ValueError("query must not be empty")

    target = resolve_workspace_path(path)
    if not target.exists():
        raise FileNotFoundError(f"No such path: {path}")

    max_results = max(1, min(int(max_results), 200))
    files = [target] if target.is_file() else iter_search_files(target)
    matches = []

    for file_path in files:
        if len(matches) >= max_results:
            break
        matches.extend(search_file(file_path, query, max_results - len(matches)))

    return json.dumps(
        {"query": query, "path": path, "matches": matches, "truncated": len(matches) >= max_results},
        ensure_ascii=False,
        indent=2,
    )


@tool("edit_file")
def edit_file(path, old_string, new_string):
    if not old_string:
        raise ValueError("old_string must not be empty")

    target = resolve_workspace_path(path)
    if not target.exists():
        raise FileNotFoundError(f"No such file: {path}")
    if not target.is_file():
        raise IsADirectoryError(f"Not a file: {path}")

    try:
        text = target.read_text(encoding="utf-8")
    except UnicodeDecodeError:
        raise ValueError(f"File is not valid UTF-8 text: {path}")

    matches = text.count(old_string)
    if matches == 0:
        raise ValueError("old_string was not found")
    if matches > 1:
        raise ValueError(f"old_string matched {matches} times; provide a unique replacement target")

    target.write_text(text.replace(old_string, new_string, 1), encoding="utf-8")
    return f"Edited {path}: replaced 1 occurrence."


def iter_paths(directory):
    for child in sorted(directory.iterdir(), key=lambda item: item.name.lower()):
        if child.is_dir():
            if child.name not in SEARCH_SKIP_DIRS:
                yield child
                yield from iter_paths(child)
        elif child.is_file():
            yield child


def iter_search_files(directory):
    for child in iter_paths(directory):
        if child.is_file():
            yield child


def search_file(file_path, query, remaining):
    if file_path.stat().st_size > MAX_SEARCH_FILE_BYTES:
        return []

    try:
        lines = file_path.read_text(encoding="utf-8").splitlines()
    except UnicodeDecodeError:
        return []

    matches = []
    relative_path = str(file_path.relative_to(WORKSPACE_ROOT))
    for line_number, line in enumerate(lines, start=1):
        if query in line:
            matches.append({"path": relative_path, "line": line_number, "text": line})
            if len(matches) >= remaining:
                break
    return matches

import getpass
import json
import os
import sys
import urllib.error
import urllib.request
from datetime import datetime
from pathlib import Path

from prompt_toolkit import PromptSession
from prompt_toolkit.history import FileHistory

if __package__ in (None, ""):
    sys.path.append(str(Path(__file__).resolve().parents[1]))

from langbridge_cli.tools import TOOL_SCHEMAS, TOOLS


API_URL = "https://api.openai.com/v1/responses"
DEFAULT_MODEL = "gpt-5.1-codex"
CONFIG_DIR = Path.home() / ".langbridge"
CONFIG_PATH = CONFIG_DIR / "config.json"
HISTORY_PATH = CONFIG_DIR / "history"
MAX_AGENT_STEPS = 20
WORKSPACE_ROOT = Path.cwd().resolve()
RUNS_DIR = WORKSPACE_ROOT / "session-history"
WRITE_TOOLS = {"edit_file", "install_python_packages"}


def main():
    api_key = load_api_key()
    model = os.environ.get("LANGBRIDGE_MODEL", DEFAULT_MODEL)
    run_log_path = create_run_log_path()
    session = create_prompt_session() if sys.stdin.isatty() else None

    messages = [
        {
            "role": "system",
            "content": "You are langbridge-cli, a concise coding agent. Help the user implement software step by step.",
        }
    ]

    print(f"langbridge-cli using {model}")
    print(f"Agent loop log: {run_log_path}")
    print("Type /exit to quit.\n")

    while True:
        try:
            text = read_user_input(session)
        except KeyboardInterrupt:
            print()
            continue
        except EOFError:
            break

        if text.strip() == "/exit":
            break

        messages.append({"role": "user", "content": text})
        reply = run_agent(api_key, model, messages, run_log_path)
        messages.append({"role": "assistant", "content": reply})
        print(f"\n{reply}\n")


def load_api_key():
    api_key = os.environ.get("OPENAI_API_KEY")
    if api_key:
        return api_key

    if CONFIG_PATH.exists():
        return json.loads(CONFIG_PATH.read_text())["api_key"]

    api_key = getpass.getpass("Enter Codex API key: ")
    CONFIG_PATH.parent.mkdir(parents=True, exist_ok=True)
    CONFIG_PATH.write_text(json.dumps({"api_key": api_key}, indent=2))
    CONFIG_PATH.chmod(0o600)
    return api_key


def create_run_log_path():
    RUNS_DIR.mkdir(parents=True, exist_ok=True)
    timestamp = datetime.now().strftime("%Y%m%d-%H%M%S")
    return RUNS_DIR / f"{timestamp}.json"


def create_prompt_session():
    CONFIG_DIR.mkdir(parents=True, exist_ok=True)
    return PromptSession(history=FileHistory(str(HISTORY_PATH)))


def read_user_input(session):
    if session is not None:
        return session.prompt("langbridge> ")
    return input("langbridge> ")


def run_agent(api_key, model, messages, run_log_path):
    agent_input = list(messages)

    for step in range(MAX_AGENT_STEPS):
        write_agent_input_log(run_log_path, step, agent_input)
        data = create_response(api_key, model, agent_input)
        output = data.get("output", [])
        tool_calls = [item for item in output if item.get("type") == "function_call"]

        if not tool_calls:
            return extract_output_text(output)

        agent_input.extend(output)
        for call in tool_calls:
            tool_output = run_tool_call(call)
            agent_input.append(tool_output)

    return "Agent stopped because it reached the maximum tool-call steps."


def create_response(api_key, model, agent_input):
    body = json.dumps({"model": model, "input": agent_input, "tools": TOOL_SCHEMAS}).encode()
    request = urllib.request.Request(
        API_URL,
        data=body,
        headers={
            "Authorization": f"Bearer {api_key}",
            "Content-Type": "application/json",
        },
        method="POST",
    )

    try:
        with urllib.request.urlopen(request) as response:
            data = json.loads(response.read())
    except urllib.error.HTTPError as error:
        data = json.loads(error.read())
        raise RuntimeError(data.get("error", {}).get("message", "OpenAI request failed"))

    return data


def run_tool_call(call):
    name = call.get("name")
    call_id = call.get("call_id")

    try:
        arguments = json.loads(call.get("arguments") or "{}")
        if name not in TOOLS:
            raise ValueError(f"Unknown tool: {name}")
        if name in WRITE_TOOLS and not approve_write_tool(name, arguments):
            raise PermissionError(f"{name} was not approved")
        output = TOOLS[name](**arguments)
    except Exception as error:
        output = f"Tool error: {error}"

    return {"type": "function_call_output", "call_id": call_id, "output": output}


def approve_write_tool(name, arguments):
    if not sys.stdin.isatty():
        return False

    print(f"\nApprove write tool: {name}")
    print(json.dumps(arguments, ensure_ascii=False, indent=2))
    answer = input("Run this tool? [y/N] ")
    return answer.strip().lower() in {"y", "yes"}


def write_agent_input_log(run_log_path, step, agent_input):
    record = {"step": step, "agent_input": agent_input}
    records = []
    if run_log_path.exists():
        records = json.loads(run_log_path.read_text(encoding="utf-8"))

    records.append(record)
    run_log_path.write_text(
        json.dumps(records, ensure_ascii=False, indent=2) + "\n",
        encoding="utf-8",
    )


def extract_output_text(output):
    return "".join(
        content["text"]
        for item in output
        for content in item.get("content", [])
        if content["type"] == "output_text"
    )


if __name__ == "__main__":
    main()

